#include<cstdio>
#include<cmath> 
using namespace std;

int main()
{
	int n,a[1001],b[1001],c[1001],s=0,i,j;
	scanf("%d",&n);
	scanf("%d%d%d",&a[1],&b[1],&c[1]);
	for(i=2;i<=n;i++)
	{
		scanf("%d%d%d",&a[i],&b[i],&c[i]);
	    for(j=1;j<i;j++)
	    {
	    		if((abs(c[j]-c[i])<=5)&&(abs(b[j]-b[i])<=5)&&(abs(a[j]-a[i])<=5)&&(abs(a[j]+b[j]+c[j]-a[i]-b[i]-c[i])<=10))
		        {
			        s++;
		        }
	    }

	}
	printf("%d",s);
	return 0;
}
